The existing file already has `test_special`, `test_tiny`, `test_known`, `test_large`, `test_quadrant`, `test_hard`, and dense sweeps. I'll focus on what those miss: ULP neighbors of key values, the full pi-grid, explicit bit patterns for boundary transitions, and small-argument fast-path thresholds.

```c
static void test_representative_100(void)
{
    float pi = 3.14159265358979323846f;

    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundaries (4) --- */
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(FLT_MAX);
    emit(-FLT_MAX);

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3f7fffffu);  /* 1 ULP below 1.0 */
    emit(1.0f);
    emit_u(0x3f800001u);  /* 1 ULP above 1.0 */
    emit_u(0x3f7ffff0u);  /* 16 ULPs below 1.0 */
    emit_u(0x3f800010u);  /* 16 ULPs above 1.0 */
    emit(-1.0f);
    emit_u(0xbf7fffffu);  /* 1 ULP toward zero from -1.0 */
    emit_u(0xbf800001u);  /* 1 ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching boundaries (6) --- */
    emit_u(0x3effffffu);  /* 1 ULP below 0.5 */
    emit(0.5f);
    emit_u(0x3f000001u);  /* 1 ULP above 0.5 */
    emit_u(0x3fffffffu);  /* 1 ULP below 2.0 */
    emit(2.0f);
    emit_u(0x40000001u);  /* 1 ULP above 2.0 */

    /* --- Section 6: Pi-grid angles not in existing test_known (14) --- */
    /* test_known covers pi/6, pi/4, pi/3, pi/2, pi, 2pi and some negatives */
    emit(2.0f * pi / 3.0f);   /* 2pi/3  ~ 2.094 */
    emit(3.0f * pi / 4.0f);   /* 3pi/4  ~ 2.356 */
    emit(5.0f * pi / 6.0f);   /* 5pi/6  ~ 2.618 */
    emit(7.0f * pi / 6.0f);   /* 7pi/6  ~ 3.665 */
    emit(5.0f * pi / 4.0f);   /* 5pi/4  ~ 3.927 */
    emit(4.0f * pi / 3.0f);   /* 4pi/3  ~ 4.189 */
    emit(5.0f * pi / 3.0f);   /* 5pi/3  ~ 5.236 */
    emit(7.0f * pi / 4.0f);   /* 7pi/4  ~ 5.497 */
    emit(11.0f * pi / 6.0f);  /* 11pi/6 ~ 5.760 */
    emit(-2.0f * pi / 3.0f);  /* -2pi/3 */
    emit(-3.0f * pi / 4.0f);  /* -3pi/4 */
    emit(-5.0f * pi / 6.0f);  /* -5pi/6 */
    emit(-5.0f * pi / 4.0f);  /* -5pi/4 */
    emit(-7.0f * pi / 4.0f);  /* -7pi/4 */

    /* --- Section 7: Range reduction stress (8) --- */
    emit_u(0x4b400000u);  /* 12582912.0 = 3*2^22, near pi multiples */
    emit_u(0x4dc90fdbu);  /* ~100*pi as nearest float */
    emit_u(0x501b74eeu);  /* ~1000*pi as nearest float */
    emit(1.0e7f);
    emit(1.0e10f);
    emit(-1.0e7f);
    emit(-1.0e10f);
    emit_u(0x4b000000u);  /* 8388608.0 = 2^23, mantissa precision boundary */

    /* --- Section 8: ULP neighbors of key trig boundaries (15) --- */
    /* pi/2: sin transitions through +1 */
    emit_u(0x3fc90fdau);  /* 1 ULP below pi/2 */
    emit_u(0x3fc90fdbu);  /* pi/2 exact float */
    emit_u(0x3fc90fdcu);  /* 1 ULP above pi/2 */
    /* pi: sin transitions through ~0 (nearest float to pi != pi) */
    emit_u(0x40490fdau);  /* 1 ULP below pi */
    emit_u(0x40490fdbu);  /* pi exact float */
    emit_u(0x40490fdcu);  /* 1 ULP above pi */
    /* 3pi/2: sin transitions through -1 */
    emit_u(0x4096cbe3u);  /* 1 ULP below 3pi/2 */
    emit_u(0x4096cbe4u);  /* 3pi/2 exact float */
    emit_u(0x4096cbe5u);  /* 1 ULP above 3pi/2 */
    /* 2pi: sin transitions through ~0 */
    emit_u(0x40c90fdau);  /* 1 ULP below 2pi */
    emit_u(0x40c90fdbu);  /* 2pi exact float */
    emit_u(0x40c90fdcu);  /* 1 ULP above 2pi */
    /* -pi/2: sin transitions through -1 */
    emit_u(0xbfc90fdau);  /* 1 ULP toward zero from -pi/2 */
    emit_u(0xbfc90fdbu);  /* -pi/2 exact float */
    emit_u(0xbfc90fdcu);  /* 1 ULP away from zero from -pi/2 */

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    /* Many implementations use sin(x)~x for |x| below some threshold */
    emit_u(0x39800000u);  /* 2^-12 = 0.000244, common threshold */
    emit_u(0xb9800000u);  /* -2^-12 */
    emit_u(0x33800000u);  /* 2^-24 ~ float machine epsilon */
    emit_u(0xb3800000u);  /* -2^-24 */
    emit_u(0x3a800000u);  /* 2^-10 = 0.000977 */
    emit_u(0xba800000u);  /* -2^-10 */
    emit_u(0x3c800000u);  /* 2^-6 = 0.015625 */
    emit_u(0xbc800000u);  /* -2^-6 */

    /* --- Section 10: Polynomial branch and hard reduction cases (24) --- */
    /* ULP neighbors of pi/8 (midpoint of primary polynomial interval [0, pi/4]) */
    emit_u(0x3ec90fdau);  /* 1 ULP below pi/8 */
    emit_u(0x3ec90fdbu);  /* pi/8 exact float */
    emit_u(0x3ec90fdcu);  /* 1 ULP above pi/8 */
    /* ULP neighbors of pi/4 (sin/cos polynomial switchover boundary) */
    emit_u(0x3f490fdau);  /* 1 ULP below pi/4 */
    emit_u(0x3f490fdbu);  /* pi/4 exact float */
    emit_u(0x3f490fdcu);  /* 1 ULP above pi/4 */
    /* 3pi/8: exercises cos-path reconstruction (sin(x) = cos(pi/2 - x)) */
    emit(3.0f * pi / 8.0f);
    emit(-3.0f * pi / 8.0f);
    /* Large k*pi: sin ~ 0 but float k*pi != k*pi, heavy cancellation */
    emit(3.0f * pi);
    emit(-3.0f * pi);
    emit(4.0f * pi);
    emit(5.0f * pi);
    /* Odd half-multiples: sin = +-1 after reduction, tests quadrant selection */
    emit(5.0f * pi / 2.0f);   /* 5pi/2, sin = +1 */
    emit(7.0f * pi / 2.0f);   /* 7pi/2, sin = -1 */
    emit(-5.0f * pi / 2.0f);  /* -5pi/2, sin = -1 */
    /* 2^23 and 2^24 boundaries: where integer-only float precision breaks reduction */
    emit_u(0x4b7fffffu);  /* just below 16777216.0 = 2^24 */
    emit_u(0x4b800000u);  /* 16777216.0 = 2^24, float has no fraction */
    emit_u(0xcb800000u);  /* -2^24 */
    emit_u(0x4a000000u);  /* 2097152.0 = 2^21 */
    emit_u(0x4a800000u);  /* 4194304.0 = 2^22 */
    emit_u(0x4b000001u);  /* 8388609.0 = 2^23 + 1, first non-representable successor */
    emit_u(0xcb000001u);  /* -(2^23 + 1) */
    emit(3.0f);           /* between pi/2 and pi, primary polynomial region */
    emit(-3.0f);
}
