/*
 * sin() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly sin  (test_sin_opt.elf)
 *   2. Linked with toolchain's default sin       (test_sin_ref.elf)
 * Run both, diff the output to find discrepancies.
 *
 * Compile with -DEN_PERF for cycle-count benchmarking on FPGA.
 * test_representative_100() is shared between accuracy and perf modes.
 * The dense sweeps run in accuracy mode only.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
static volatile double g_acc;
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x)
{
#ifdef EN_PERF
    g_acc += sin(x);
#else
    double r = sin(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* 100 analytically representative test points                        */
/* Shared between accuracy mode and the EN_PERF benchmark window.     */
/* ------------------------------------------------------------------ */
static void test_representative_100(void)
{
    double pi = 3.14159265358979323846;

    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundaries (4) --- */
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(DBL_MAX);
    emit(-DBL_MAX);

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* 1 ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* 1 ULP above 1.0 */
    emit_u(0x3feffffffffffff0ULL);  /* 16 ULPs below 1.0 */
    emit_u(0x3ff0000000000010ULL);  /* 16 ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* 1 ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* 1 ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching boundaries (6) --- */
    emit_u(0x3fdfffffffffffffULL);  /* 1 ULP below 0.5 */
    emit(0.5);
    emit_u(0x3fe0000000000001ULL);  /* 1 ULP above 0.5 */
    emit_u(0x3fffffffffffffffULL);  /* 1 ULP below 2.0 */
    emit(2.0);
    emit_u(0x4000000000000001ULL);  /* 1 ULP above 2.0 */

    /* --- Section 6: Pi-grid angles not in primary coverage (14) --- */
    /* test_known covered: pi/6, pi/4, pi/3, pi/2, pi, 2pi, 3pi/2 and negatives */
    emit(2.0 * pi / 3.0);   /* 2pi/3  ~ 2.094 */
    emit(3.0 * pi / 4.0);   /* 3pi/4  ~ 2.356 */
    emit(5.0 * pi / 6.0);   /* 5pi/6  ~ 2.618 */
    emit(7.0 * pi / 6.0);   /* 7pi/6  ~ 3.665 */
    emit(5.0 * pi / 4.0);   /* 5pi/4  ~ 3.927 */
    emit(4.0 * pi / 3.0);   /* 4pi/3  ~ 4.189 */
    emit(5.0 * pi / 3.0);   /* 5pi/3  ~ 5.236 */
    emit(7.0 * pi / 4.0);   /* 7pi/4  ~ 5.497 */
    emit(11.0 * pi / 6.0);  /* 11pi/6 ~ 5.760 */
    emit(-2.0 * pi / 3.0);  /* -2pi/3 */
    emit(-3.0 * pi / 4.0);  /* -3pi/4 */
    emit(-5.0 * pi / 6.0);  /* -5pi/6 */
    emit(-5.0 * pi / 4.0);  /* -5pi/4 */
    emit(-7.0 * pi / 4.0);  /* -7pi/4 */

    /* --- Section 7: Range reduction stress (8) --- */
    /* Double sin() uses Payne-Hanek for large |x|; must include > 1e15. */
    emit(1.0e15);
    emit(1.0e16);
    emit(1.0e17);
    emit(-1.0e15);
    emit(-1.0e17);
    emit(1.23456789012345e15);                   /* irrational large */
    emit_u(0x432921fb54442d18ULL);               /* 2^51*(pi/2): Payne-Hanek hard case */
    emit(1.0e20);

    /* --- Section 8: ULP neighbors of key trig boundaries (15) --- */
    /* pi/2: sin transitions through +1 */
    emit_u(0x3ff921fb54442d17ULL);  /* 1 ULP below pi/2 */
    emit_u(0x3ff921fb54442d18ULL);  /* pi/2 exact double */
    emit_u(0x3ff921fb54442d19ULL);  /* 1 ULP above pi/2 */
    /* pi: nearest double to pi gives sin != 0 */
    emit_u(0x400921fb54442d17ULL);  /* 1 ULP below pi */
    emit_u(0x400921fb54442d18ULL);  /* pi exact double */
    emit_u(0x400921fb54442d19ULL);  /* 1 ULP above pi */
    /* 3pi/2: sin transitions through -1 */
    emit_u(0x4012d97c7f3321d1ULL);  /* 1 ULP below 3pi/2 */
    emit_u(0x4012d97c7f3321d2ULL);  /* 3pi/2 exact double */
    emit_u(0x4012d97c7f3321d3ULL);  /* 1 ULP above 3pi/2 */
    /* 2pi: sin transitions through ~0 */
    emit_u(0x401921fb54442d17ULL);  /* 1 ULP below 2pi */
    emit_u(0x401921fb54442d18ULL);  /* 2pi exact double */
    emit_u(0x401921fb54442d19ULL);  /* 1 ULP above 2pi */
    /* -pi/2: sin transitions through -1 */
    emit_u(0xbff921fb54442d17ULL);  /* 1 ULP toward zero from -pi/2 */
    emit_u(0xbff921fb54442d18ULL);  /* -pi/2 exact double */
    emit_u(0xbff921fb54442d19ULL);  /* 1 ULP away from zero from -pi/2 */

    /* --- Section 9: Small-argument fast-path boundaries (8) --- */
    /* Many implementations take sin(x)~x for |x| below a threshold. */
    emit_u(0x3fb0000000000000ULL);  /* 2^-12 = 0.000244, common threshold */
    emit_u(0xbfb0000000000000ULL);  /* -2^-12 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26 ~ half of double machine epsilon */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
    emit_u(0x3f80000000000000ULL);  /* 2^-7 = 0.0078125 */
    emit_u(0xbf80000000000000ULL);  /* -2^-7 */
    emit_u(0x3f20000000000000ULL);  /* 2^-13 */
    emit_u(0xbf20000000000000ULL);  /* -2^-13 */

    /* --- Section 10: Polynomial branch and hard reduction cases (24) --- */
    /* ULP neighbors of pi/8 (midpoint of primary polynomial interval [0, pi/4]) */
    emit_u(0x3fd921fb54442d17ULL);  /* 1 ULP below pi/8 */
    emit_u(0x3fd921fb54442d18ULL);  /* pi/8 exact double */
    emit_u(0x3fd921fb54442d19ULL);  /* 1 ULP above pi/8 */
    /* ULP neighbors of pi/4 (sin/cos polynomial switchover boundary) */
    emit_u(0x3fe921fb54442d17ULL);  /* 1 ULP below pi/4 */
    emit_u(0x3fe921fb54442d18ULL);  /* pi/4 exact double */
    emit_u(0x3fe921fb54442d19ULL);  /* 1 ULP above pi/4 */
    /* 3pi/8: cos-path polynomial via sin(x) = cos(pi/2 - x) */
    emit(3.0 * pi / 8.0);
    emit(-3.0 * pi / 8.0);
    /* Large k*pi: sin ~ 0 but double k*pi != k*pi, catastrophic cancellation */
    emit(3.0 * pi);
    emit(-3.0 * pi);
    emit(4.0 * pi);
    emit(5.0 * pi);
    emit(10.0 * pi);
    /* Odd half-multiples: sin = +-1 after reduction, tests quadrant selection */
    emit(5.0 * pi / 2.0);   /* sin = +1 */
    emit(7.0 * pi / 2.0);   /* sin = -1 */
    emit(-5.0 * pi / 2.0);  /* sin = -1 */
    /* Scaled pi/2 patterns: Payne-Hanek reduction at varying magnitude */
    emit_u(0xc32921fb54442d18ULL);  /* -(2^51*(pi/2)) */
    emit_u(0x419921fb54442d18ULL);  /* 2^26*(pi/2) */
    emit_u(0xc19921fb54442d18ULL);  /* -(2^26*(pi/2)) */
    emit_u(0x416921fb54442d18ULL);  /* 2^23*(pi/2), near mantissa precision limit */
    /* Medium-large range */
    emit(1.0e10);
    emit(-1.0e10);
    /* Primary polynomial region, non-pi inputs */
    emit(3.0);
    emit(-3.0);
}

/* ------------------------------------------------------------------ */
/* Dense sweeps — accuracy mode only, not benchmarked                 */
/* ------------------------------------------------------------------ */

/* Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
static void test_sweep(void)
{
    double hi = 4.0 * 3.14159265358979323846;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* Sample [0, pi/4] every 4503599627370496 ULP (~200 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x3fe921fb54442d18ULL; /* pi/4 */
    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
        emit_u(b);
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u(g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

